import React, { useState, useEffect } from 'react';
import './Navbar.css';

const LINKS = [
  { label: 'Home',      href: '#hero' },
  { label: 'Our Story', href: '#story' },
  { label: 'Events',   href: '#events' },
  { label: 'Gallery',  href: '#gallery' },
  { label: 'Wishes',   href: '#wishes' },
  { label: 'RSVP',     href: '#rsvp' },
];

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen]         = useState(false);
  const [active, setActive]     = useState('#hero');

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 60);
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const handleLink = (href) => {
    setActive(href);
    setOpen(false);
    document.querySelector(href)?.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <nav
      className={`navbar ${scrolled ? 'navbar--scrolled' : ''} ${open ? 'navbar--open' : ''}`}
      role="navigation"
      aria-label="Main navigation"
    >
      <div className="navbar__inner">
        {/* Logo */}
        <button
          className="navbar__logo"
          onClick={() => handleLink('#hero')}
          aria-label="Back to top"
        >
          D <span>&amp;</span> C
        </button>

        {/* Desktop links */}
        <ul className="navbar__links" role="menubar">
          {LINKS.map(({ label, href }) => (
            <li key={href} role="none">
              <button
                role="menuitem"
                className={`navbar__link ${active === href ? 'navbar__link--active' : ''}`}
                onClick={() => handleLink(href)}
              >
                {label}
              </button>
            </li>
          ))}
        </ul>

        {/* Hamburger */}
        <button
          className="navbar__burger"
          aria-label={open ? 'Close menu' : 'Open menu'}
          aria-expanded={open}
          onClick={() => setOpen(o => !o)}
        >
          <span /><span /><span />
        </button>
      </div>

      {/* Mobile drawer */}
      <div className="navbar__drawer" aria-hidden={!open}>
        <ul role="menu">
          {LINKS.map(({ label, href }) => (
            <li key={href} role="none">
              <button
                role="menuitem"
                className={`navbar__drawer-link ${active === href ? 'navbar__drawer-link--active' : ''}`}
                onClick={() => handleLink(href)}
              >
                {label}
              </button>
            </li>
          ))}
        </ul>
      </div>
    </nav>
  );
}
